class Admin_Model_CustomMeal extends Admin_Model_Base_CustomMeal
{

    public static function getSearchMeals($query) {
        $result = Doctrine_Query::create()
            ->from('Admin_Model_CustomMeal object')
            ->andWhere('object.Name LIKE ?', '%' . $query . '%')
            ->groupBy('object.Name')
            ->limit(10)
            ->execute();

        return $result;

    }

}